/** Vo Lam Thuy Vi */
const User = require("../model/userModel");
const OTP = require("../model/optModel");
const LogoutToken = require("../model/logoutTokenModel");
const { generateToken, JWT_EXPIRES_IN } = require("../config/jwt");
const createError = require("http-errors");
const crypto = require("crypto");
const nodemailer = require("nodemailer");
const jwt = require("jsonwebtoken");
const fs = require("fs");
const path = require("path");
const { OAuth2Client } = require("google-auth-library");

// Google OAuth client - replace with your actual client ID
const GOOGLE_CLIENT_ID =
  "141368667605-uuh35jb8su9oui61geubhuvg9h47cns8.apps.googleusercontent.com";
const googleClient = new OAuth2Client(GOOGLE_CLIENT_ID);

exports.register = async (userData) => {
  try {
    const existingUser = await User.findOne({ email: userData.email });
    if (existingUser) {
      throw createError(400, "Email already in use");
    }

    const user = await User.create({
      full_name: userData.full_name,
      email: userData.email,
      password: userData.password,
      phone: userData.phone || "",
      avatar: userData.avatar || "",
      role: userData.role || "trader",
      isVerify: false,
    });

    // Generate OTP for email verification
    const otp = Math.floor(100000 + Math.random() * 900000).toString();
    const expiryTime = new Date(Date.now() + 10 * 60 * 1000); // 10 minutes

    await OTP.create({
      user_id: user._id,
      code: otp,
      purpose: "verify_account",
      expires_at: expiryTime,
    });

    // Send OTP via email (in a real application)
    // For now, we'll return it in the response
    if (process.env.GMAIL_USER && process.env.GMAIL_PASS) {
      await sendVerificationEmail(user.full_name, user.email, otp);
    } else {
      console.warn(
        "⚠️ Email credentials not configured. OTP will be returned in response only."
      );
    }

    const token = generateToken(user._id);

    const { password, ...userWithoutPassword } = user.toObject();

    return { user: userWithoutPassword, token, otp };
  } catch (error) {
    throw error;
  }
};

exports.verifyEmail = async (email, otp) => {
  try {
    const user = await User.findOne({ email });
    if (!user) {
      throw createError(404, "No user found with that email");
    }

    const otpRecord = await OTP.findOne({
      user_id: user._id,
      code: otp,
      purpose: "verify_account",
      is_used: false,
      expires_at: { $gt: new Date() },
    });

    if (!otpRecord) {
      throw createError(400, "Invalid or expired OTP");
    }

    // Update user verification status
    user.isVerify = true;
    await user.save();

    // Mark OTP as used
    otpRecord.is_used = true;
    await otpRecord.save();

    return { user };
  } catch (error) {
    throw error;
  }
};

exports.login = async (email, password) => {
  try {
    if (!email || !password) {
      throw createError(400, "Please provide email and password");
    }

    const user = await User.findOne({ email }).select("+password");

    if (!user || !(await user.comparePassword(password))) {
      throw createError(401, "Incorrect email or password");
    }

    if (user.is_banned) {
      throw createError(
        403,
        "Your account has been banned. Please contact support."
      );
    }

    if (!user.isVerify) {
      throw createError(
        403,
        "Please verify your email address before logging in"
      );
    }

    const token = generateToken(user._id);

    user.password = undefined;

    return { user, token };
  } catch (error) {
    throw error;
  }
};

exports.logout = async (userId, token) => {
  try {
    let expiryTime;
    if (JWT_EXPIRES_IN.endsWith("d")) {
      //1d = 1 day
      const days = parseInt(JWT_EXPIRES_IN);
      expiryTime = new Date(Date.now() + days * 24 * 60 * 60 * 1000);
    } else if (JWT_EXPIRES_IN.endsWith("h")) {
      const hours = parseInt(JWT_EXPIRES_IN);
      expiryTime = new Date(Date.now() + hours * 60 * 60 * 1000);
    } else {
      expiryTime = new Date(Date.now() + 12 * 60 * 60 * 1000);
    }

    await LogoutToken.create({
      token,
      user_id: userId,
      expires_at: expiryTime,
    });

    return true;
  } catch (error) {
    throw error;
  }
};

exports.forgotPassword = async (email) => {
  try {
    const user = await User.findOne({ email });
    if (!user) {
      throw createError(404, "No user found with that email");
    }
    const token = generateToken(user._id);
    const link = `http://localhost:9999/reset-password?token=${token}`;
    if (process.env.EMAIL_USERNAME && process.env.EMAIL_PASSWORD) {
      await sendVerificationEmail(user.full_name, email, link, true);
    } else {
      console.warn("⚠️ Email not sent. Reset link: " + link);
    }
    return { email };
  } catch (error) {
    throw error;
  }
};

exports.resetPassword = async (user, newPassword) => {
  try {
    user.password = newPassword;
    await user.save();

    return { message: "Password reset successfully" };
  } catch (error) {
    throw createError(400, "Invalid or expired reset token");
  }
};

exports.getCurrentUser = async (userId) => {
  try {
    const user = await User.findById(userId);
    if (!user) {
      throw createError(404, "User not found");
    }
    return user;
  } catch (error) {
    throw error;
  }
};

exports.changePassword = async (userId, currentPassword, newPassword) => {
  const user = await User.findById(userId).select("+password");
  if (!user) throw createError(404, "User not found");

  const isMatch = await user.comparePassword(currentPassword);
  if (!isMatch) throw createError(401, "Invalid current password");

  user.password = newPassword;
  await user.save();
};

const sendVerificationEmail = async (
  name,
  email,
  otpOrLink,
  isSendForgot = false
) => {
  try {
    // Check if email credentials are configured
    if (!process.env.EMAIL_USERNAME || !process.env.EMAIL_PASSWORD) {
      console.warn(
        `⚠️ Email not sent (missing credentials). ${
          isSendForgot ? "Reset link" : "OTP"
        }: ${otpOrLink}`
      );
      return true; // Don't throw error, just skip email sending
    }

    console.log(
      `Sending ${isSendForgot ? "reset link" : "OTP"} to email: ${email}`
    );

    const transporter = nodemailer.createTransport({
      service: "gmail",
      auth: {
        user: process.env.EMAIL_USERNAME,
        pass: process.env.EMAIL_PASSWORD,
      },
    });

    const templatePath = path.join(
      __dirname,
      "..",
      "views",
      "email-templates",
      isSendForgot ? "reset-password.html" : "verify-email.html"
    );

    let htmlContent;
    try {
      htmlContent = fs.readFileSync(templatePath, "utf8");
    } catch (error) {
      // Fallback HTML if template file is missing
      htmlContent = isSendForgot
        ? `
          <html>
            <body style="font-family: Arial, sans-serif;">
              <h2>Password Reset Request</h2>
              <p>Hello ${name},</p>
              <p>Please click the link below to reset your password:</p>
              <p><a href="${otpOrLink}">${otpOrLink}</a></p>
              <p>This link will expire in 24 hours.</p>
            </body>
          </html>
        `
        : `
          <html>
            <body style="font-family: Arial, sans-serif;">
              <h2>Email Verification</h2>
              <p>Hello ${name},</p>
              <p>Your OTP code is: <strong>${otpOrLink}</strong></p>
              <p>This code will expire in 10 minutes.</p>
            </body>
          </html>
        `;
    }

    htmlContent = htmlContent.replace(/{{name}}/g, name);
    htmlContent = htmlContent.replace(/{{otpCode}}/g, otpOrLink);

    await transporter.sendMail({
      from: process.env.EMAIL_FROM,
      to: email,
      subject: isSendForgot ? "Reset Your Password" : "Verify Your Email",
      html: htmlContent,
    });

    return true;
  } catch (error) {
    console.error("Error sending email:", error);
    throw error;
  }
};

exports.googleLogin = async (token) => {
  try {
    // Verify Google token
    const ticket = await googleClient.verifyIdToken({
      idToken: token,
      audience:
        "141368667605-uuh35jb8su9oui61geubhuvg9h47cns8.apps.googleusercontent.com",
    });

    const payload = ticket.getPayload();
    const { email, name, picture } = payload;

    // Check if user exists
    let user = await User.findOne({ email });

    if (!user) {
      // Create new user if not exists
      user = await User.create({
        full_name: name,
        email,
        password: crypto.randomBytes(20).toString("hex"), // Generate random password
        avatar: picture,
        isVerify: true, // Google account is already verified
        role: "trader",
        phone: "",
      });
    }

    // Generate JWT token
    const jwtToken = generateToken(user._id);

    return { user, token: jwtToken };
  } catch (error) {
    throw createError(401, "Invalid Google token");
  }
};

